func onclick(s, v, c string) {
	start = !start
	if start {
		closing = false
		status = "Stop!"

		fmt.Println("submit", s, v, c)
		sp, vk, ct := loadConfig()
		if sp != s || vk != v || ct != c {
			saveConfig(s, v, c)
		}
		go func() {
			for {
				cl = client.NewRPClient(s, v, c, "", nil, 60)
				status = "Stop!"
				refreshCh <- struct{}{}
				cl.Start()
				logs.Warn("client closed, reconnecting in 5 seconds...")
				if closing {
					return
				}
				status = "Reconnecting..."
				refreshCh <- struct{}{}
				time.Sleep(time.Second * 5)
			}
		}()
	} else {

		status = "Start!"
		closing = true
		if cl != nil {
			go cl.Close()
			cl = nil
		}
	}
	refreshCh <- struct{}{}
}
